1	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
2	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const CURSED_SURCHARGE_RATE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const PROCESSING_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  potion: 40,
11	  amulet: 60,
12	  staff: 80,
13	  rune: 25,
14	};
15	
16	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
17	
18	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
19	
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PREMIUM = 60;
22	
23	const totalBasePremium = (items: Item[]): number => {
24	  const groups = new Map<string, Item[]>();
25	  for (const item of items) {
26	    const group = groups.get(item.type) ?? [];
27	    group.push(item);
28	    groups.set(item.type, group);
29	  }
30	
31	  let total = 0;
32	  for (const [, group] of groups) {
33	    if (group.length === COMPONENT_BLOCK_SIZE && itemBasePremium(group[0]) === 25) {
34	      total += COMPONENT_BLOCK_PREMIUM;
35	    } else {
36	      total += group.reduce((sum, item) => sum + itemBasePremium(item), 0);
37	    }
38	  }
39	  return total;
40	};
41	
42	const sumSurcharge = (items: Item[], appliesTo: (item: Item) => boolean, rate: number): number =>
43	  items.filter(appliesTo).reduce((sum, item) => sum + itemBasePremium(item) * rate, 0);
44	
45	const conditionalDiscount = (applies: boolean, amount: number, rate: number): number =>
46	  applies ? amount * rate : 0;
47	
48	export function quote(customer: { yearsWithMHPCO: number }, items: Item[], contractIndex: number): number {
49	  const basePremium = totalBasePremium(items);
50	  const cursedSurcharge = sumSurcharge(items, (item) => item.cursed, CURSED_SURCHARGE_RATE);
51	  const enchantmentSurcharge = sumSurcharge(items, (item) => item.enchantment >= 5, HIGH_ENCHANTMENT_SURCHARGE_RATE);
52	  const itemTotal = basePremium + cursedSurcharge + enchantmentSurcharge;
53	
54	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
55	  const followUpDiscount = conditionalDiscount(contractIndex > 0, basePremium, FOLLOW_UP_DISCOUNT_RATE);
56	  const loyaltyDiscount = conditionalDiscount(customer.yearsWithMHPCO >= 2, basePremium, LOYALTY_DISCOUNT_RATE);
57	  const policyAdjustment = firstInsuranceSurcharge - followUpDiscount - loyaltyDiscount;
58	
59	  return itemTotal + policyAdjustment + PROCESSING_FEE;
60	}
61	
62	export function claim() {
63	  return undefined;
64	}
